	// STRY0116812
	buildOUMap: function(widgetId, map, grOU, fields) {
		var isGHA = new UserInfoScripts().UserHasRole('x_153465_discovert.tasker_organizational_admin');
		var currentUser = gs.getUserID();
		var ouO = this.getTaskListTreeLevelO(grOU, fields, grOU.office_level, widgetId);
		this.setAdminBooleans(grOU, ouO, isGHA, currentUser);
        // the top node of the tree cannot have a parent
        delete ouO.parent;
		map.push(ouO);

		// technically level not used for Office as it is a field in the org
		this.getOUs(widgetId, fields, ouO.level, map, ouO, ouO.sys_id, isGHA, currentUser);
	},

    // this is a recursive function used to load all tasks in the task tree into the Data for widgets
    getOUs: function(widgetId, fields, level, map, ouO, sys_id, isGHA, currentUser) {
        var grOU = new GlideRecordSecure('x_153465_discovert_discover_office_hierarchy');
        grOU.addQuery('parent', sys_id);
        grOU.orderBy('level_order');
        grOU.orderBy('office_name');
        grOU.query();
        while (grOU.next()) {
			var office_level = parseInt(grOU.office_level);
            var ouLevelO = this.getTaskListTreeLevelO(grOU, fields, office_level, widgetId);
			this.setAdminBooleans(grOU, ouLevelO, isGHA, currentUser);
            map.push(ouLevelO);
            this.getOUs(widgetId, fields, office_level, map, ouLevelO, grOU.getUniqueValue(), isGHA, currentUser);
        }
    },

	setAdminBooleans: function(grOU, ouO, isGHA, currentUser){
		var isOUAdmin = false;
		var ouHAValue = grOU.getValue('u_ou_hierarchy_administrators');
		// DFCT0011118 
		if(ouHAValue && ouHAValue.indexOf(currentUser)>=0){
			isOUAdmin = true;
		}
		ouO.isAdmin = (isGHA || isOUAdmin);
	},

	// 2.7.0 | 2021-07-06 | mmcc | STRY0102408 Task Tree Manager tool tip displays Unicode; combined Task and Template widget data code
    buildTaskMap: function(widgetId, map, gr, fields) {
        var taskO = this.getTaskListTreeLevelO(gr, fields, 1, widgetId);

        // the top node of the tree cannot have a parent
        delete taskO.parent;

        if (widgetId == 'discovertasker-processtemplatetreegraph') {
            // STRY0097904
            taskO.process_level_map = gr.tasker_process_definition.process_level.getDisplayValue();
            taskO.process_name_map = gr.number.toString() + ' - ' + gr.short_description.toString();
        }

        map.push(taskO);

        if (widgetId == 'discovertasker-processtemplatetreegraph') {
            this.getTemplateTasks(widgetId, fields, map, taskO.level, taskO, taskO.sys_id);
        } else {
            this.getTasks(widgetId, fields, taskO.level, map, taskO, taskO.sys_id);
        }
    },


