	// this is a recursive function used to load all tasks in the task tree into the Data for widgets
    getTasks: function(widgetId, fields, level, map, taskO, sys_id) {
        var grTask = new GlideRecord('x_153465_discovert_route_task_instance');
        grTask.addQuery('parent', sys_id);
        grTask.orderBy('order');
        grTask.orderBy('number');
        grTask.query();
        var parentAfterAllChildren = true;
        while (grTask.next()) {
            if (!grTask.canRead()) {
                continue;
            }
            var taskLevelO = this.getTaskListTreeLevelO(grTask, fields, level, widgetId);
            map.push(taskLevelO);
            this.getTasks(widgetId, fields, level + 1, map, taskLevelO, grTask.getUniqueValue());
            if (widgetId == 'discovertasker-recursivetasktreegraph') {
                if (taskLevelO.suspense_date > taskO.suspense_date) {
                    parentAfterAllChildren = false;
                    taskLevelO.warning.isSuspenseDateAfterParent = true;
                }
            }
        }
        if (widgetId == 'discovertasker-recursivetasktreegraph') {
            // STRY0095748 - no suspensedate warning
            taskO.warning.noSuspenseDate = (taskO.suspense_date == '' || taskO.suspense_date == null);
			// STRY0122880 
            taskO.warning.waitStatewithNoSubtasks = ((taskO.u_wait_for_subtasks_to_finish && 
														(taskO.calchaschildren == 0)) ||
													(taskO.u_wait_for_subtasks_to_finish && 
														(taskO.calchaschildren != 0) && 
														(taskO.state==-3) && 
														(taskO.u_active_subtasks==0))
													);
            taskO.warning.isSuspenseDateAfterChildren = parentAfterAllChildren;
            taskO.warning.primaryAssigneeEmpty = (taskO.primary_assignee == '' || taskO.primary_assignee == null);
            taskO.warning.assignedMemberEmpty = (taskO.assigned_to == '' || taskO.assigned_to == null);
        }
    },
    //Get Template Tasks Level 1++
    getTemplateTasks: function(widgetId, fields, map, level, TemplateTaskO, sys_id) {
        var grTempTask = new GlideRecordSecure('x_153465_discovert_route_tasks');
        grTempTask.addQuery('parent', sys_id);
        grTempTask.orderBy('route_order');
        grTempTask.orderBy('number');
        grTempTask.query();

        while (grTempTask.next()) {
            var taskLevelO = this.getTaskListTreeLevelO(grTempTask, fields, level, widgetId);
			// STRY0117609 - if parent task is inactive, make task inactive
			if(!TemplateTaskO.active){
				taskLevelO.inActiveDueToParent = taskLevelO.active && !TemplateTaskO.active;
				taskLevelO.active = TemplateTaskO.active;
			}
            map.push(taskLevelO);
            this.getTemplateTasks(widgetId, fields, map, level + 1, taskLevelO, grTempTask.getUniqueValue());
        }
        if (widgetId == 'discovertasker-processtemplatetreegraph') {
            TemplateTaskO.warning.waitStatewithNoSubtasks = (TemplateTaskO.u_wait_for_subtasks_to_finish && (TemplateTaskO.calchaschildren == 0));

            TemplateTaskO.warning.primaryAssigneeEmpty = (TemplateTaskO.primary_assignee == '' || TemplateTaskO.primary_assignee == null);

            // STRY0095897
            TemplateTaskO.warning.taskingAuthorityEmpty = (TemplateTaskO.tasking_authority == '' || TemplateTaskO.tasking_authority == null);
            TemplateTaskO.warning.primaryOfficeEmpty = (TemplateTaskO.primary_office == '' || TemplateTaskO.primary_office == null);
        }
    },
    // 2.7.0 | 2021-07-06 | mmcc | STRY0102408 Task Tree Manager tool tip displays Unicode; Task and Template widget data is same code
    getTaskListTreeLevelO: function(record, fields, level, widgetId) {
        var displayValue = '';
        var newNodeData = {};
        var sys_id = record.getUniqueValue();
        newNodeData.key = sys_id;
        newNodeData.sys_id = sys_id;
        newNodeData.level = level;
		var current_user = gs.getUserID();

		// STRY0109208, STRY0109209  - Add Create Icons
		var table = record.getRecordClassName();
		if (table == 'x_153465_discovert_route_tasks'){
			newNodeData.canCreate = new UserInfoScripts().userHasProcessRights(record);
		} else if(table == 'x_153465_discovert_route_task_instance'){
			// NOTE: this should go into script include and be called from there
			newNodeData.canCreateSubTask = new uiConditionCheck().canCreateSubTask(record);
		}
        for (var key in fields) {
            var field = fields[key];
            // 2.7.0 | 2021-07-06 | mmcc | STRY0102408 Task Tree Manager tool tip displays Unicode
            // displayValue = record.getDisplayValue(key) + '';
            if ((field.fieldName == 'u_signature_instructions') || (field.fieldName == 'instructions')) {
                displayValue = this.convertHtmlToSimpleString(record.getDisplayValue(key) + '');
            } else {
                displayValue = record.getDisplayValue(key) + '';
            }

            if (field.maxChars > 0) {
                displayValue = displayValue.toString().length > field.maxChars ? displayValue.substring(0, field.maxChars - 1) : displayValue.toString();
            }

            if (field.keyUsesDisplayOnly) {
                newNodeData[key] = displayValue;
            }
            if (field.hasValue) {
                newNodeData[key] = record.getValue(key);
            }
            if (field.hasDiplayValue) {
                newNodeData[key + '_DisplayValue'] = displayValue;
            }
			// STRY0116812
			switch (field.type){
				case 'date':
					var date_number = record[key].dateNumericValue();
					newNodeData[key] = date_number;
					break;
				case 'time':
					var time_number = 0;
					if(record.getValue(key) && record[key].dateNumericValue()>0){
						var gdTime = new GlideDateTime(record.getValue(key));  
						var localTime = gdTime.getLocalTime();
						time_number = (localTime.getHourOfDayLocalTime() * 60 + localTime.getMinutesLocalTime() * 60 + localTime.getSeconds()) * 1000;
					}
					newNodeData[key] = time_number;
					break;
				case 'boolean':
					var boolean_value = record[key] == 1 || record[key] == true;
					newNodeData[key] = boolean_value;
					break;
				case 'number':
					newNodeData[key] = record.getValue(key)==null?0:parseInt(record.getValue(key));
					break;
				// STRY0114453 
				case 'profile':
				case 'photo':
					var photoInfo = this.loadPhotoInfo(newNodeData[key], false);
					newNodeData[key + '_photoName'] = photoInfo.name;
					if(photoInfo.photo){
						newNodeData[key + '_photo'] = photoInfo.photo;
					}

					// STRY0114453 
					if(field.type=='profile'){
						var profileInfo = this.loadProfileInfo(newNodeData[key]);
						newNodeData[key + '_profile'] = profileInfo;
					}

					break;
				case 'list':
					var list_value = record[key] == null || record[key] == undefined ? '': record[key];
					newNodeData[key] = list_value;

					// load the list into the Map
					newNodeData[key + '_list'] = [];
					var listArray = displayValue.split(',');
					for(var i=0; i<listArray.length; i++){
						var arrayItem = {};
						arrayItem.displayName = listArray[i];
						if(arrayItem.displayName != null && arrayItem.displayName != undefined && arrayItem.displayName != ''){
							newNodeData[key + '_list'].push(arrayItem);
						}
					}
					break;
            }

        }

        // These are the custom fields in this data set, compare with other data sets and determine best way to bring together.
		// STRY0113880 - DFCT0010761 - changed if to case
		switch(widgetId){
			case 'discovertasker-recursivetasktreelist':
				// Load the text for the Task Tree List
				// 2.7.0 | 2021-07-06 | mmcc | STRY0102408 Task Tree Manager tool tip displays Unicode
				// newNodeData.text = this.getTaskTreeListTitleNode(newNodeData, newNodeData.parent, newNodeData.task_name, newNodeData.primary_assignee, newNodeData.assigned_to, newNodeData.state, newNodeData.order);
				newNodeData.text = this.getTaskTreeListTitleNode(newNodeData);

				// we will expand all on initial page load
				newNodeData.expanded = true;
				// NOTE you are here, there is an issue with leaf nodes having the down chevron when they should not	
				// this should be removed
				// 2.7.0 | 2021-07-06 | mmcc | STRY0102408 Task Tree Manager tool tip displays Unicode Decimal Codes when entering 
				break;
			case 'discovertasker-recursivetasktreegraph':
				// Load the name value for the Task Tree Graph
				// 2.7.0 | 2021-07-06 | mmcc | STRY0102408 Task Tree Manager tool tip displays Unicode; combined Task and Template widget data code
				newNodeData.name = this.getTaskTitleNode(record);
				newNodeData.warning = {};
				newNodeData.isInboundExternalOU = !record.parent && record.tasking_authority && (record.tasking_authority.u_external_flag == true);
				newNodeData.warning.isTopSuspenseDateAfterExternalInboundDate = newNodeData.isInboundExternalOU && (record.suspense_date > record.u_external_due_date);
				newNodeData.isOutboundExternalOU = (record.outbound == true);
				newNodeData.warning.isTopSuspenseDateBeforeExternalOutboundDate = newNodeData.isOutboundExternalOU && (record.u_external_due_date > record.suspense_date);
				break;
			case 'discovertasker-processtemplatetreegraph':
				// Load the name value for the Template Task Tree Graph
				newNodeData.name = this.getTemplateTitleNode(record);
				newNodeData.warning = {};
				// STRY0110317 calculate the due date to be set using days and Time
				newNodeData.actualTime = 0;
				if(newNodeData.u_duration_days >= 0){
					newNodeData.actualTime = newNodeData.u_duration_days * 86400000;
				}
				if(newNodeData.u_duration_time_due >= 0){
					newNodeData.actualTime+= newNodeData.u_duration_time_due;
				}
				break;
			case 'discovertasker-officehierarchy':
				// Load the name value for the Office Hierarchy
				// STRY0113880 - DFCT0010761
				newNodeData.name = newNodeData.office_name + '\n  (' + newNodeData.office_abbreviation + ')';
        }

        return newNodeData;
    },

	// 2.8 | 2022-03-10 | mmcc | STRY0114453 - Org Hierarchy Full Screen- Tree Node- Avatar Control- Popover Panel; 
	// Get info about the plugin being active and if live_profile has a record get the live profile ID for the useer
	getConnectEnabled: function(userId) {
		var chat = {
			connectEnabled: false,
			liveProfileId: ''
		};

		// is chat active?
		chat.connectEnabled = GlidePluginManager().isActive('com.glide.connect');

		// Check if logged in user has a live profile for sending connect messages
		if (GlidePluginManager().isActive('com.glideapp.live_common')) {
			var liveProfileGR = new GlideRecord("live_profile");
			liveProfileGR.addQuery("document", userId);
			liveProfileGR.query();
			if (liveProfileGR.next()) {
				chat.liveProfileId = liveProfileGR.getValue("sys_id");
// 				data.liveProfileModel = $sp.getForm("live_profile", data.liveProfileID)._fields;
// 				// live_profile short_description is shown here as "Bio", so popup label/hint must reflect that
// 				if (data.liveProfileModel.short_description) {
// 					data.liveProfileModel.short_description.label = gs.getMessage("Bio");
// 					data.liveProfileModel.short_description.hint = gs.getMessage("Biography");
// 				}
			} else {
				chat.connectEnabled = false; // can't find a live profile for this user, so lets not integrate Connect
			}
		}

		return chat;
	},

