	// STRY0114453 
	loadProfileInfo: function(userGUID) {
		var userProfile = {
			sys_id: userGUID,
			name: '',
			first_name: '',
			last_name: '',
			middle_name: '',
			email: '',
			businessPhone: '',
			mobilePhone: '',
			location: '',
			time_zone: '',
			contactPageHref: '',
			photo: '',
			connectEnabled: '',
			liveProfileId: '',
			messages: {},
			icons: {}
		};

		var grUser = new GlideRecord('sys_user');
		if(grUser.get(userGUID)){
			// 2.8 | 2022-03-04 | mmcc | STRY0114453 - Org Hierarchy Full Screen- Tree Node- Avatar Control- Popover Panel; 
			//  added getDisplayValue to many, .contactPageHref, mobile phone; Changed phone to businessPhone, add call to get Connect Chat fields
			userProfile.name = grUser.getDisplayValue('name');
			userProfile.first_name = grUser.getDisplayValue('first_name');
			userProfile.last_name = grUser.getDisplayValue('last_name');
			userProfile.middle_name = grUser.getDisplayValue('middle_name');
			userProfile.email = grUser.getDisplayValue('email');
			userProfile.businessPhone = grUser.getDisplayValue('phone');
			userProfile.mobilePhone = grUser.getDisplayValue('mobile_phone');
			userProfile.location = grUser.getDisplayValue('location');
			userProfile.contactPageHref = '?id=user_profile&sys_id=' + userGUID;

			// if no user time zone, but location is loaded
			if(grUser.time_zone){
				userProfile.time_zone = grUser.getDisplayValue('time_zone'); // + '';
			} else if(grUser.location && grUser.location.time_zone){
				userProfile.time_zone = gs.getMessage("Tasker - (location) - ") + userProfile.location.time_zone;
			}
			// Connect Chat 
			var chat = this.getConnectEnabled(userGUID);
			userProfile.connectEnabled = chat.connectEnabled;
			userProfile.liveProfileId = chat.liveProfileId;
		}
		return userProfile;
	},

    // 2.7.0 | 2021-07-06 | mmcc | STRY0102408 Task Tree Manager tool tip displays Unicode
    // re-write function to use local var's; remove badgeclass and taskText.state
    getTaskTreeListTitleNode: function(newNodeData) {
        var assignedTo = '';
        var taskNameNumber = newNodeData.task_name;
        var taskText = {};

        if (newNodeData.parent != null) {
            taskNameNumber = newNodeData.order + ". " + newNodeData.task_name;
        }

        if (!!newNodeData.assigned_to && newNodeData.assigned_to != '') {
            assignedTo = '(' + newNodeData.assigned_to + ')';
        }

        taskText = {
            TaskNameNumber: taskNameNumber,
            primary_assignee: newNodeData.primary_assignee,
            assigned_to: assignedTo,
            state: newNodeData.state,
            Order: newNodeData.order
        };

        return taskText;
    },
    // SEQ - Task Details page – Displays Task Tree View Indicators
    getTaskTitleNode: function(grTask) {
        var nodeTitle = grTask.task_name.toString();
        if (grTask.parent != '') {
            nodeTitle = grTask.order.toString() + ". " + nodeTitle; // NEW
        }

        // 2.5.13: 08.12.20 | KT | SEQ | STRY0076601: SEQ - Task Details page – Displays Task Tree View Indicators 
        //if (grTask.assigned_to.getDisplayValue().toString().length > 0) nodeTitle += " (" + grTask.assigned_to.getDisplayValue().toString() + ") "; //KT: 06.09.20: Added space before (Assignee
        switch (grTask.state.getDisplayValue().toString()) {
            case 'Waiting':
                if (grTask.calchaschildren.getDisplayValue().toString() == '0'
                    //grTask.u_active_subtasks.getDisplayValue().toString() == grTask.calchaschildren.getDisplayValue().toString() && 
                )
                    nodeTitle += " - " + grTask.state.getDisplayValue().toString() + " on creating Subtasks ";
                else
                    nodeTitle += " - " + grTask.state.getDisplayValue().toString() + " on " + grTask.u_active_subtasks.getDisplayValue().toString() + " out of " + grTask.calchaschildren.getDisplayValue().toString() + " Subtasks";
                break;
            case 'Assigned':
                nodeTitle += " - " + grTask.state.getDisplayValue().toString() + " to " + grTask.assigned_to.getDisplayValue().toString();
                break;
            case 'Accepted':
                nodeTitle += " - " + grTask.state.getDisplayValue().toString() + " by " + grTask.assigned_to.getDisplayValue().toString();
                break;
            case 'Work in Progress':
                nodeTitle += " - " + grTask.state.getDisplayValue().toString() + " by " + grTask.assigned_to.getDisplayValue().toString();
                break;
            case 'In Review':
                nodeTitle += " - " + grTask.state.getDisplayValue().toString() + " by " + grTask.u_reviewer.getDisplayValue().toString() + ", Worked by " + grTask.assigned_to.getDisplayValue().toString();
                break;
            case 'Completed':
                nodeTitle += " - " + grTask.state.getDisplayValue().toString() + " by " + grTask.assigned_to.getDisplayValue().toString();
                break;
            default:
                nodeTitle += " - " + grTask.state.getDisplayValue().toString();
                break;
        }
        return nodeTitle;
    },
    // Template has to set the name a little differently than task
    getTemplateTitleNode: function(grTemplateTask) {
        var nodeTitle = grTemplateTask.number.toString() + ' - ' + grTemplateTask.short_description.toString() + ' (' + grTemplateTask.primary_assignee.getDisplayValue().toString() + ')';
        if ((grTemplateTask.parent != '') && (parseInt(grTemplateTask.route_order.getDisplayValue().toString()) > 0)) {
            nodeTitle = grTemplateTask.route_order.getDisplayValue().toString() + ". " + nodeTitle;
        }

        return nodeTitle;
    },

	// STRY0119587 - Task Form Page Layout- Layout: Requests
	// STRY0120403 changed structure to recieve single object and pass filter for all descendents
	loadRelatedLists: function(rlParms) {
		var tab_widget_related_lists = [];
		// STRY0120440
		var rlItem;
		for (var i in rlParms.f_related_lists) {
			// STRY0092475 - STRY0120440 - moved this up to set as default so the array from page options could override it
			var rlView = rlParms.view;	

			var rl = rlParms.f_related_lists[i];
			// STRY0120440
			if (rl.table == "x_153465_discovert_discover_tasker_response"){
				// NOTE: we may want to changet his based on whether single task or all descendents is the current filter
				rlView = "sp"; // override the default from tasker form with tabs for response log
			}

			// default show all related lists
			var showRL = true;
			// if documents not included, don't show attachments
			if(rl.table == "sys_attachment" ){
				// DFCT0011062 improves efficiency of what is loaded to HTML and removes all related lists except attachments if attachment is on
				if(rlParms.hideDocuments || 
					rlParms.attachmentsON == false ||
					((rl.label == "Shared Attachments") && (rlParms.attachmentSharedFolderON == false)) ||
					((rl.label == "Attachments") &&
						(rlParms.table == "x_153465_discovert_discover_routing_template") &&
						(rlParms.attachmentSharedFolderON == false))
					){
					showRL = false;
				}
			// DFCT0011062 improves efficiency of what is loaded to HTML and removes all related lists except attachments if attachment is on
			} else if(rlParms.hideRelatedLists){
				showRL = false;
			}else if(rlParms.arrRelatedLists && rlParms.arrRelatedLists.length > 0){
				// if an array of related lists was set in the widget options, then this list is not shown unless in the list
				showRL = false;
				for(var j = 0; j < rlParms.arrRelatedLists.length; j++) {
					// STRY0120440
					rlItem = rlParms.arrRelatedLists[j];
					if (rlItem.label == rl.label) {
						if(rlItem.view && rlItem.view!=''){
							// override the default view with the view passed in
							rlView = rlItem.view;
						}
						showRL = true;
						break;
					}
				}
			}
			rl.showList = showRL;
			if(!showRL){
				continue;
			}

			//------------------------------------------------------------------------------------------------------------------------
			// 2.1. CUSTOM: RELATED LIST DETAIL OPEN MODE: MODAL OR REDIRECT?
			//------------------------------------------------------------------------------------------------------------------------

			var open_row_details_in_modal = false;

			if (rlParms.table == "x_153465_discovert_route_task_instance" && rl.table == "x_153465_discovert_tasker_requests") open_row_details_in_modal = true;
			if (rl.table == "x_153465_discovert_tasker_email") open_row_details_in_modal = true;
			if (rlParms.page_id == "discovertasker_processtemplatedetails" && rlParms.table == "x_153465_discovert_route_tasks") open_row_details_in_modal = true;
			if ((rlParms.page_id == "discovertasker_detailsdrilldown") && 
				rlParms.table == "x_153465_discovert_route_task_instance") open_row_details_in_modal = true;
			if (rlParms.table == "x_153465_discovert_discover_office_hierarchy" && 
				rl.table == "x_153465_discovert_route_task_instance") open_row_details_in_modal = true;

			if (rlParms.page_id == undefined && rlParms.table == "x_153465_discovert_route_task_instance" && 
				rl.table == "x_153465_discovert_route_task_instance") {
				open_row_details_in_modal = true;
			}

			if (rlParms.table == "x_153465_discovert_discover_routing_template") open_row_details_in_modal = true;
			if (rl.table == "x_153465_discovert_discover_office_members") open_row_details_in_modal = true;
			// STRY0108170
			if (rl.table == "x_153465_discovert_tasker_requests") open_row_details_in_modal = true;

			if (rlParms.table == "x_153465_discovert_war_sar_reporting") open_row_details_in_modal = true;
			// STRY0074663
			if (rl.table == "x_153465_discovert_organizational_contacts") open_row_details_in_modal = true;

			if (rlParms.table == "x_153465_discovert_discover_tasker_response") open_row_details_in_modal = true;

			// DFCT0010784 - anything on the processing page should open in Modal
			if(rlParms.page_id == "discover_simple_processing_form" ||
				rlParms.page_id == "task_delegation_view") {
				open_row_details_in_modal = true;
			}

			//------------------------------------------------------------------------------------------------------------------------
			// 2.2. CUSTOM: RELATED LIST SORT AND DIRECTION
			//------------------------------------------------------------------------------------------------------------------------

			var o = "";
			var d = "";

			//2.5.13 | KT | REQ | STRY0073625
			if (rl.table == "x_153465_discovert_tasker_requests") {
				o = "number";
				d = "desc";
			}

			if (rl.table == "x_153465_discovert_tasker_schedule") {
				o = "next_run_date";
				d = "asc";
			}

			if (rl.table == "x_153465_discovert_discover_office_members") {
				o = "office_member";
				d = "asc";
			}

			// STRY0074663
			if (rl.table == "x_153465_discovert_organizational_contacts") {
				o = "u_user_information";
				d = "asc";
			}

			if (rl.table == "x_153465_discovert_route_task_instance") {
				o = "task_order";
				d = "asc";
			}

			// 2.8 | 2022-08-01 | mmcc | DFCT0011122 - Page Task Requests needs to match the standard layout for flexing header-body-footer; pass the whole related list item
			// DFCT0010477
			rl.title = this._getTabTitle(rl);

			// STRY0092475 - this is a special case as we want to order the list to put the newest ask at the top instead of listing them by task order
			if (rl.table == "x_153465_discovert_route_task_instance" && rlParms.table == "x_153465_discovert_discover_routing_template") {
				// STRY0097809
				rlView = "sp";
				rl.title = rl.label;
				o = "number";
				d = "desc";
				// STRY0092475 - related list uses a relationshiop and for some reason the rl.field value is undefined for relationships
				rl.field = 'u_parent_template';
			}

			//------------------------------------------------------------------------------------------------------------------------
			// 2.4. CUSTOM: RELATED LIST FILTER
			//------------------------------------------------------------------------------------------------------------------------
			var filter = rl.field + "=" + rlParms.rec.sys_id;
			// STRY0059424 | Include Attachments since we dropped attachment properties
			if ((rl.table == "sys_attachment") && (rl.label == "Shared Attachments") && (rlParms.attachmentSharedFolderON == true)) {
				// STRY0063505 |	Modified to set this above based on table
				filter = 'table_sys_id' + "=" + rlParms.sharedAttachSys_ID;
			} else {
				if ((rl.table == "sys_attachment") && (rl.label == "Attachments")) {
					// STRY0063505 |	Modified to set this above based on table
					filter = 'table_sys_id' + "=" + rlParms.myAttachSys_ID;
				}
			}
			rl.filter = filter;

			// STRY0059145 | The previous implementation was using just rl.table for the target inthe HTML for loading data and counts.
			// Any time the same table is added 2 times in the HTML, the target will be the same for both tables.  
			// a new field was created, rl.targetId, by concatenating rl.table with rl.label(without spaces).
			// this new field will be used instead of rl.table in the target fields of the HTML
			rl.targetId = rl.table + rl.label.replace(/ /g, "_");

			// STRY0046028 - determine if user can create for the related list
			var userInfoScript = new UserInfoScripts();
			switch (rl.table) {
				case "x_153465_discovert_discover_office_members":
					rl.canCreate = userInfoScript.userCanCreateMem(rlParms.rec.sys_id);
					break;
				case "x_153465_discovert_discover_office_hierarchy":
					rl.canCreate = userInfoScript.userCanCreateOU(rlParms.rec.sys_id);
					break;
				case "x_153465_discovert_route_tasks":
					rl.canCreate = userInfoScript.userHasProcessRights(rlParms.rec);
					break;
				case "x_153465_discovert_discover_routing_template":
					rl.canCreate = userInfoScript.userHasProcessRights(rlParms.rec);
					break;
				case "x_153465_discovert_tasker_schedule":
					// STRY0082332 - FIX: Template Designers can create Template Schedules
					rl.canCreate = new uiConditionCheck().runTemplateUIAction(rlParms.rec);
					break;
				case "x_153465_discovert_organizational_contacts":
					rl.canCreate = true;
					break;
				case "x_153465_discovert_route_task_instance":
					rl.canCreate = rlParms.canCreateSubTask;

					break;
					// 2.7.2 | 2022-01-26 | mmcc | STRY0110656 - UI- Fixed Header and Button Bars on ALL Modals and lists
					// This will control showing a New button on the menu row for Tasker Emails tab
				case 'x_153465_discovert_tasker_email':
					rl.canCreate = rlParms.emailEnabled;
					break;
				default:
					rl.canCreate = false;

			}			
			//------------------------------------------------------------------------------------------------------------------------
			// 2.5. CUSTOM: WIDGET PARAMETERS
			//------------------------------------------------------------------------------------------------------------------------
			// NOTE: moved below the setting of canCreate so that can be used in the show_new
			var params = {
				// STRY0120159 
				showStatesMultipleBar: rlParms.showStatesMultipleBar,
				hideTaskFilter: rlParms.hideTaskFilter,
				task_id: rlParms.task_id,
				parentField: rl.field,
				o: o,
				d: d,
				table: rl.table,
				filter: filter,
				// STRY0107408
				show_new: rl.canCreate,
				open_new_in_modal: true,
				//STRY0092475: 04/01/2020
				view: rlView,
				title: rl.title,
				// 2.7.1 | 2021-12-10 | mmcc | STRY0115408 - Long text needs to be shortened and have an ellipsis added 
				isModal: rlParms.isModal,
				// 2.8 | 2022-08-01 | mmcc | DFCT0011122 - Page Task Requests needs to match the standard layout for flexing header-body-footer; add bifold
				bifold: rlParms.bifold,
				open_row_details_in_modal: open_row_details_in_modal
				//show_breadcrumbs: true
			};

			//------------------------------------------------------------------------------------------------------------------------
			// 2.5. CUSTOM: RELATED LIST CALL WIDGET 
			//------------------------------------------------------------------------------------------------------------------------
			rl.widget = $sp.getWidget('discovertasker-widget-data-table', params);
			tab_widget_related_lists.push(rl);
		}
		return tab_widget_related_lists;
	},

	// 2.8 | 2022-08-01 | mmcc | DFCT0011122 - Page Task Requests needs to match the standard layout for flexing header-body-footer; pass the whole related list item
	_getTabTitle: function(itemRelatedList) {
		var tabTitle = '';

		// 2.8 | 2022-08-01 | mmcc | DFCT0011122 - Page Task Requests needs to match the standard layout for flexing header-body-footer; 
		// TODO - Multi language
		switch (itemRelatedList.table) {
			case "x_153465_discovert_route_task_instance":
				tabTitle = 'Subtasks';
				break;
			case "x_153465_discovert_route_tasks":
				tabTitle = 'Subtasks';
				break;
			case "x_153465_discovert_discover_office_hierarchy":
				tabTitle = 'Sub OUs';
				break;
			case "x_153465_discovert_discover_office_members":
				tabTitle = 'OU Members';
				break;
			case "x_153465_discovert_discover_routing_template":
				tabTitle = 'Template Instances';
				break;
				// STRY0074663
			case "x_153465_discovert_organizational_contacts":
				tabTitle = 'Contacts';
				break;
				// DFCT0010477
			case "x_153465_discovert_tasker_email":
				tabTitle = 'Tasker Emails';
				break;
			default:
				// 2.8 | 2022-08-01 | mmcc | DFCT0011122 - Page Task Requests needs flexing; if plural exists use it else use label
				if (itemRelatedList.plural && itemRelatedList.plural != '') {
					tabTitle = itemRelatedList.plural;
				} else {
					tabTitle = itemRelatedList.label;
				}

		}
		return tabTitle;
	},

    type: 'TaskWidgetData'
};
